import React, { useEffect, useState, useMemo } from 'react';
import classNames from 'classnames';
import styles from './Header.module.scss';

const Header = () => {
  const [isMoved, setIsMoved] = useState(false);
  let isDebounce = false;
  const moveListener = () => {
    if (!isDebounce) {
      isDebounce = true;
      setTimeout(() => {
        isDebounce = false;
      }, 50);
      if (window.scrollY && window.scrollY > 10) {
        setIsMoved(true);
      } else {
        setIsMoved(false);
      }
    }
  };

  useEffect(() => {
    window.addEventListener('scroll', moveListener, { passive: true });

    return () => {
      window.removeEventListener('scroll', moveListener);
    };
  }, []);

  return useMemo(() => (
    <div className={classNames(styles.root, { [styles.moved]: isMoved })}>
      <img src="https://dan-it.com.ua/wp-content/themes/danIT/img/logo.png" alt="Logo" />
      <span>Welcome to Front-end</span>
    </div>
  ), [isMoved]);
};

Header.propTypes = {};

Header.defaultProps = {};

export default Header;
