import React from 'react';
import {
  Switch,
  Route,
} from 'react-router-dom';
import Home from '../pages/Home';
import WhatIsFrontend from '../pages/WhatIsFrontend';
import IDE from '../pages/IDE';

const Routes = () => (
  <Switch>
    <Route path="/what-is-frontend">
      <WhatIsFrontend />
    </Route>

    <Route path="/ide">
      <IDE />
    </Route>

    <Route path="/">
      <Home />
    </Route>
  </Switch>
);

export default Routes;
